#!/bin/bash
echo "==========================================="
echo "  WebToAPK - Auto Deploy Script"
echo "==========================================="
echo ""

cd /var/www/html || { echo "ERROR: /var/www/html not found!"; exit 1; }

echo "[1/5] Backing up existing files..."
sudo mkdir -p /var/www/html/backup_
for f in config.php db.php api.php build_server.php build_worker.php generate.php download_apk.php index.php; do
    if [ -f "$f" ]; then
        sudo cp "$f" "/var/www/html/backup_/$f"
    fi
done
echo "   Backup done!"

echo "[2/5] Decoding and extracting files..."
echo "" | base64 -d > /tmp/deploy_update.zip
cd /var/www/html
sudo unzip -o /tmp/deploy_update.zip
echo "   Files extracted!"

echo "[3/5] Setting permissions..."
sudo chown www-data:www-data *.php
sudo chmod 644 *.php
sudo chmod 755 build_worker.php
sudo chown www-data:www-data database.sqlite 2>/dev/null
echo "   Permissions set!"

echo "[4/5] Restarting Apache..."
sudo systemctl restart apache2
echo "   Apache restarted!"

echo "[5/5] Verifying deployment..."
echo ""
echo "--- File Check ---"
for f in config.php db.php api.php build_server.php build_worker.php generate.php download_apk.php index.php; do
    if [ -f "$f" ]; then
        SIZE=$(stat -c%s "$f")
        echo "  [OK] $f ($SIZE bytes)"
    else
        echo "  [FAIL] $f NOT FOUND!"
    fi
done

echo ""
echo "--- Config Check ---"
grep -q "ENABLE_APK_BUILD', true" config.php && echo "  [OK] APK Build = ENABLED" || echo "  [FAIL] APK Build NOT enabled!"
grep -q "ENABLE_GITHUB_BUILD', false" config.php && echo "  [OK] GitHub Build = DISABLED" || echo "  [FAIL] GitHub still enabled!"

echo ""
echo "--- Build Environment ---"
php -r "
require_once '/var/www/html/config.php';
require_once '/var/www/html/build_server.php';
\\80 75 3 4 20 0 0 0 8 0 114 5 140 92 210 93 37 123 162 11 0 0 192 46 0 0 7 0 0 0 97 112 105 46 112 104 112 237 90 221 115 219 54 18 127 207 76 254 7 196 227 41 229 156 44 57 73 243 112 78 157 140 98 203 31 151 196 210 201 114 50 119 174 202 129 41 72 226 153 34 89 16 178 163 164 254 223 111 23 31 36 64 81 178 106 187 237 75 245 224 49 129 221 197 98 177 251 195 238 146 63 189 75 39 233 211 39 205 231 207 159 62 33 207 73 171 123 66 218 241 48 77 194 88 144 81 194 201 23 118 153 133 130 17 145 192 220 7 178 159 196 215 140 11 198 37 117 151 39 215 225 144 101 164 215 62 235 75 94 26 4 44 203 144 90 76 24 9 108 234 230 211 39 79 159 112 246 235 44 228 204 79 226 128 17 15 230 71 225 184 1 26 120 111 112 118 194 232 144 241 154 7 171 8 22 139 237 254 60 101 187 132 166 105 20 6 84 132 73 220 252 95 150 196 222 214 155 130 180 37 23 220 70 14 158 68 219 173 40 74 110 182 59 60 28 135 241 46 121 126 55 233 39 38 38 201 48 219 37 221 206 89 191 78 142 218 240 167 211 237 159 116 78 207 238 102 62 150 147 192 108 43 44 217 158 62 9 71 164 182 233 159 181 123 159 219 189 11 175 215 254 247 57 216 200 255 212 238 31 119 14 188 1 217 219 219 35 94 190 16 249 14 22 130 31 251 26 138 218 14 10 184 69 25 155 52 192 93 147 61 178 233 131 102 23 158 122 6 246 119 239 96 8 85 118 199 60 101 199 236 38 20 193 4 214 87 115 185 248 128 102 96 245 107 26 133 67 42 152 183 171 70 241 55 161 241 48 98 159 245 76 13 53 48 83 151 156 209 43 235 217 22 69 99 26 205 191 85 72 106 169 137 181 5 101 179 241 152 101 98 81 208 153 154 88 95 144 160 98 150 85 200 145 227 75 197 216 34 198 161 152 204 46 253 101 146 142 228 244 239 144 119 57 11 163 225 82 113 239 113 246 14 105 133 196 33 27 209 89 36 44 41 44 152 36 4 195 194 103 113 144 12 89 237 162 152 195 31 152 86 186 174 71 246 222 146 17 141 50 86 47 17 76 97 150 142 153 36 240 78 98 233 30 68 121 78 131 180 174 105 24 209 203 136 233 17 112 118 227 63 117 162 143 191 78 244 241 193 63 114 35 117 226 216 176 78 28 19 20 203 15 114 79 55 